import { Component, OnInit } from '@angular/core';
import { TranslateService } from '@ngx-translate/core';

@Component({ selector: 'app-root', templateUrl: './app.component.html' })
export class AppComponent implements OnInit {
  constructor(private translate: TranslateService) {}

  ngOnInit(): void {
    this.translate.onLangChange.subscribe(event => {
      // Keep the html[lang] attribute in sync with the active locale
      document.documentElement.lang = event.lang;
    });
  }
}

// src/app/core/language.service.ts
import { Injectable, Inject } from '@angular/core';
import { DOCUMENT } from '@angular/common';

@Injectable({ providedIn: 'root' })
export class LanguageService {
  private readonly supportedLangs = ['en', 'es', 'fr', 'de', 'zh-Hans'];

  constructor(@Inject(DOCUMENT) private doc: Document) {}

  setLanguage(lang: string): void {
    const normalized = this.supportedLangs.includes(lang) ? lang : 'en';
    this.doc.documentElement.lang = normalized;
    localStorage.setItem('userLang', normalized);
  }

  detectInitialLanguage(): string {
    const stored = localStorage.getItem('userLang');
    if (stored && this.supportedLangs.includes(stored)) return stored;

    // Fall back to browser preference
    const browserLang = navigator.language.split('-')[0];
    return this.supportedLangs.includes(browserLang) ? browserLang : 'en';
  }
}
